index c0cf1a7db726..8d722ebebf3b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3298,16 +3298,30 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
   if (Value *V = foldIsPowerOf2OrZero(RHS, LHS, IsAnd, Builder))
     return V;

-  // TODO: One of these directions is fine with logical and/or, the other could
-  // be supported by inserting freeze.
-  if (!IsLogical) {
-    // E.g. (icmp slt x, 0) | (icmp sgt x, n) --> icmp ugt x, n
-    // E.g. (icmp sge x, 0) & (icmp slt x, n) --> icmp ult x, n
+  // E.g. (icmp slt x, 0) | (icmp sgt x, n) --> icmp ugt x, n
+  // E.g. (icmp sge x, 0) & (icmp slt x, n) --> icmp ult x, n
+  // For logical and/or, we must ensure RangeEnd is not poison. Since the
+  // original select short-circuits, a poison RangeEnd in the combined icmp
+  // would introduce poison where there was none.
+  auto IsRangeEndSafe = [&](ICmpInst *Cmp0, ICmpInst *Cmp1) {
+    Value *Input = Cmp0->getOperand(0);
+    Value *RangeEnd;
+    if (Cmp1->getOperand(0) == Input)
+      RangeEnd = Cmp1->getOperand(1);
+    else if (Cmp1->getOperand(1) == Input)
+      RangeEnd = Cmp1->getOperand(0);
+    else
+      return false;
+    return isGuaranteedNotToBeUndefOrPoison(RangeEnd);
+  };
+  if (!IsLogical || IsRangeEndSafe(LHS, RHS)) {
     if (Value *V = simplifyRangeCheck(LHS, RHS, /*Inverted=*/!IsAnd))
       return V;
+  }

-    // E.g. (icmp sgt x, n) | (icmp slt x, 0) --> icmp ugt x, n
-    // E.g. (icmp slt x, n) & (icmp sge x, 0) --> icmp ult x, n
+  // E.g. (icmp sgt x, n) | (icmp slt x, 0) --> icmp ugt x, n
+  // E.g. (icmp slt x, n) & (icmp sge x, 0) --> icmp ult x, n
+  if (!IsLogical || IsRangeEndSafe(RHS, LHS)) {
     if (Value *V = simplifyRangeCheck(RHS, LHS, /*Inverted=*/!IsAnd))
       return V;
   }
